<thead>
<tr>
<th>Package</th>
<th>Description</th>
</tr>
</thead>
<tbody>
<tr>
<td><code v-pre>@ghentcdh/annotation-core</code></td>
<td>Shared types, Zod schemas, and configuration utilities</td>
</tr>
<tr>
<td><code v-pre>@ghentcdh/annotation-editor</code></td>
<td>Vue 3 annotation editor component</td>
</tr>
<tr>
<td><code v-pre>@ghentcdh/annotation-api</code></td>
<td>NestJS module for annotation definition services</td>
</tr>
</tbody>
</table>
